function stat(label, value) {
  return `<div class="stat"><div class="stat-label"><span>${label}</span><span>${value}%</span></div><div class="bar"><span style="width:${value}%"></span></div></div>`;
}

function renderCart() {
  const items = cartItems();
  const list = $("[data-cart-list]");
  const summary = $("[data-summary]");
  if (!items.length) {
    list.innerHTML = '<div class="empty">Корзина пока пустая. В каталоге уже ждут UR, SSR и спокойные SR-карты для первого набора.</div>';
    summary.innerHTML = `<h2>Итого</h2><div class="sum-line"><span>Товары</span><strong>0</strong></div><div class="sum-line total"><span>К оплате</span><strong>${money(0)}</strong></div><a class="btn btn-primary" href="catalog.html">В каталог</a>`;
    return;
  }
  const total = subtotal();
  const discount = promoDiscount(total);
  list.innerHTML = items.map(({ product: item, qty }) => `<article class="cart-item"><img src="${item.image}" alt="${item.name}"><div><h3>${item.name}</h3><p class="desc">${item.collection}, ${item.rarity}, ${item.condition}</p><strong>${money(item.price)}</strong></div><div class="qty"><button type="button" data-qty="${item.id}" data-diff="-1">-</button><strong>${qty}</strong><button type="button" data-qty="${item.id}" data-diff="1">+</button><button class="icon-btn" type="button" data-remove="${item.id}" aria-label="Удалить">${icon.trash}</button></div></article>`).join("");
  summary.innerHTML = `<h2>Итого</h2><div class="sum-line"><span>Товары</span><strong>${cartCount()}</strong></div><div class="sum-line"><span>Сумма</span><strong>${money(total)}</strong></div><div class="sum-line"><span>Промокод</span><strong>${discount ? `-${money(discount)}` : "нет"}</strong></div><div class="promo-row"><input class="field" data-promo-input placeholder="SEKAI5 или FOIL10" value="${activePromo()}"><button class="btn btn-small" data-apply-promo type="button">ОК</button></div><div class="sum-line total"><span>К оплате без доставки</span><strong>${money(total - discount)}</strong></div><div class="checkout-note"><strong>Что дальше</strong><span>На оформлении выберите доставку. Редкие карты поедут в протекторе, топлоадере и жесткой упаковке.</span></div><a class="btn btn-primary" href="checkout.html">${icon.arrow} Оформить</a>`;
}

