function collectionProgressView() {
  const owned = idSet(STORE.owned);
  const grouped = {};
  products().forEach((item) => {
    grouped[item.slug] ??= { title: item.collection, total: 0, owned: 0 };
    grouped[item.slug].total += 1;
    if (owned.has(item.id)) grouped[item.slug].owned += 1;
  });
  const rows = Object.values(grouped).sort((a, b) => b.owned - a.owned || a.title.localeCompare(b.title));
  return `<div class="progress-list">${rows.map((row) => {
    const percent = row.total ? Math.round(row.owned / row.total * 100) : 0;
    return `<article class="progress-item"><div><strong>${row.title}</strong><span>${row.owned} из ${row.total} карт</span></div><div class="progress-track"><span style="width:${percent}%"></span></div><b>${percent}%</b></article>`;
  }).join("")}</div>`;
}

