function createOrder(form) {
  const items = cartItems();
  if (!items.length) {
    toast("Корзина пуста");
    return;
  }
  const data = new FormData(form);
  const delivery = DELIVERY.find((item) => item.id === data.get("delivery")) || DELIVERY[0];
  const base = subtotal();
  const discount = promoDiscount(base);
  const deliveryPrice = base - discount >= 15000 ? 0 : delivery.price;
  const order = {
    id: `KS-${Date.now().toString().slice(-6)}`,
    created: new Date().toISOString(),
    status: "создан",
    customer: { name: data.get("name"), phone: data.get("phone"), city: data.get("city"), address: data.get("address") },
    delivery: delivery.id,
    deliveryTitle: delivery.title,
    payment: data.get("payment"),
    items: items.map(({ product: item, qty }) => ({ id: item.id, name: item.name, qty, price: item.price })),
    subtotal: base,
    discount,
    deliveryPrice,
    total: base - discount + deliveryPrice
  };
  const orders = read(STORE.orders, []);
  orders.unshift(order);
  write(STORE.orders, orders);
  localStorage.setItem(STORE.lastOrder, order.id);
  setCart({});
  location.href = `thanks.html?order=${order.id}`;
}

function bindGlobalEvents() {
  document.addEventListener("click", (event) => {
    const theme = event.target.closest("[data-theme-toggle]");
    if (theme) {
      event.preventDefault();
      toggleTheme();
      return;
    }
    const closeModal = event.target.closest("[data-modal-close]") || (event.target.classList?.contains("modal-backdrop") ? event.target : null);
    if (closeModal) {
      $(".modal-backdrop")?.remove();
      return;
    }
    const quick = event.target.closest("[data-quick]");
    if (quick) {
      event.preventDefault();
      event.stopPropagation();
      quickView(quick.dataset.quick);
      return;
    }
    const owned = event.target.closest("[data-owned]");
    if (owned) {
      event.preventDefault();
      event.stopPropagation();
      const result = toggleStoredSet(STORE.owned, owned.dataset.owned);
      owned.classList.toggle("is-active", result.set.has(owned.dataset.owned));
      toast(result.set.has(owned.dataset.owned) ? "Добавлено в мою коллекцию" : "Убрано из моей коллекции");
      if (document.body.dataset.page === "account") accountPage();
      return;
    }
    const galleryButton = event.target.closest("[data-gallery-view]");
    if (galleryButton) {
      const root = galleryButton.closest("[data-gallery-root]");
      const stage = root?.querySelector("[data-gallery-stage]");
      const image = root?.querySelector("[data-gallery-image]");
      const note = root?.querySelector("[data-gallery-note]");
      if (stage && image) {
        image.src = galleryButton.dataset.src;
        stage.classList.toggle("is-back", galleryButton.dataset.galleryView === "back");
        stage.classList.toggle("is-photo", galleryButton.dataset.galleryView === "photo");
        stage.classList.toggle("is-real-photo", galleryButton.dataset.realPhoto === "true");
        root.querySelectorAll("[data-gallery-view]").forEach((button) => button.classList.toggle("active", button === galleryButton));
        const notes = {
          front: "Лицевая сторона: арт, редкость и общий вид карты.",
          back: "Рубашка карты: общий дизайн для серии Карт Секай.",
          photo: galleryButton.dataset.realPhoto === "true" ? "Фото-версия: физическая карта на поверхности." : "Фото-вид: превью карты на поверхности для оценки пропорций."
        };
        if (note) note.textContent = notes[galleryButton.dataset.galleryView] || notes.front;
      }
      return;
    }
    const wait = event.target.closest("[data-wait]");
    if (wait) {
      event.preventDefault();
      event.stopPropagation();
      const waits = new Set(read(STORE.wait, []));
      waits.add(wait.dataset.wait);
      write(STORE.wait, [...waits]);
      toast("Карта добавлена в ожидание рестока");
      return;
    }
    const orderStatus = event.target.closest("[data-order-status]");
    if (orderStatus) {
      updateOrderStatus(orderStatus.dataset.orderStatus, orderStatus.dataset.statusNext);
      return;
    }
    if (event.target.closest("[data-export-store]")) {
      exportStoreData();
      return;
    }
    const add = event.target.closest("[data-add]");
    if (add) {
      event.preventDefault();
      event.stopPropagation();
      addToCart(add.dataset.add);
      return;
    }
    const bundle = event.target.closest("[data-bundle]");
    if (bundle) {
      addBundle(bundle.dataset.bundle);
      return;
    }
    const fav = event.target.closest("[data-fav]");
    if (fav) {
      event.preventDefault();
      event.stopPropagation();
      const set = idSet(STORE.fav);
      set.has(fav.dataset.fav) ? set.delete(fav.dataset.fav) : set.add(fav.dataset.fav);
      saveSet(STORE.fav, set);
      fav.classList.toggle("is-active", set.has(fav.dataset.fav));
      toast(set.has(fav.dataset.fav) ? "Добавлено в избранное" : "Убрано из избранного");
      return;
    }
    const compare = event.target.closest("[data-compare]");
    if (compare) {
      event.preventDefault();
      event.stopPropagation();
      const set = idSet(STORE.compare);
      if (set.has(compare.dataset.compare)) set.delete(compare.dataset.compare);
      else if (set.size >= 4) toast("В сравнении максимум 4 карты");
      else set.add(compare.dataset.compare);
      saveSet(STORE.compare, set);
      compare.classList.toggle("is-active", set.has(compare.dataset.compare));
      return;
    }
    const card = event.target.closest("[data-card]");
    if (card && !event.target.closest("a, button")) location.href = `product.html?id=${card.dataset.card}`;
    if (event.target.closest("[data-menu]")) $(".nav")?.classList.toggle("open");
    const qty = event.target.closest("[data-qty]");
    if (qty) {
      const value = cart();
      const next = Math.max(0, (value[qty.dataset.qty] || 0) + Number(qty.dataset.diff));
      if (next) value[qty.dataset.qty] = next;
      else delete value[qty.dataset.qty];
      setCart(value);
      renderCart();
    }
    const remove = event.target.closest("[data-remove]");
    if (remove) {
      const value = cart();
      delete value[remove.dataset.remove];
      setCart(value);
      renderCart();
    }
    if (event.target.closest("[data-apply-promo]")) {
      const code = ($("[data-promo-input]")?.value || "").trim().toUpperCase();
      if (code && !PROMOS[code]) toast("Такого промокода нет");
      else {
        if (code) localStorage.setItem(STORE.promo, code);
        else localStorage.removeItem(STORE.promo);
        renderCart();
      }
    }
    if (event.target.closest("[data-clear-compare]")) {
      saveSet(STORE.compare, new Set());
      comparePage();
    }
    if (event.target.closest("[data-reset-store]")) {
      [STORE.cart, STORE.fav, STORE.compare, STORE.orders, STORE.admin, STORE.wait, STORE.owned, STORE.theme, STORE.promo, STORE.lastOrder].forEach((key) => localStorage.removeItem(key));
      toast("Данные витрины очищены");
      adminPage();
    }
  });

  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape") $(".modal-backdrop")?.remove();
    const card = event.target.closest?.("[data-card]");
    if (card && (event.key === "Enter" || event.key === " ")) {
      event.preventDefault();
      location.href = `product.html?id=${card.dataset.card}`;
    }
    const search = event.target.closest?.("[data-site-search]");
    if (search && event.key === "Enter") {
      const value = search.value.trim();
      location.href = value ? `catalog.html?q=${encodeURIComponent(value)}` : "catalog.html";
    }
  });

  document.addEventListener("submit", async (event) => {
    if (event.target.matches("[data-form]")) {
      event.preventDefault();
      event.target.reset();
      toast("Сообщение принято. Мы свяжемся с вами.");
    }
    if (event.target.matches("[data-checkout-form]")) {
      event.preventDefault();
      createOrder(event.target);
    }
    if (event.target.matches("[data-import-form]")) {
      event.preventDefault();
      try {
        importStoreData($("[data-export-output]")?.value || "");
        toast("Данные витрины импортированы");
        adminPage();
      } catch {
        toast("Не удалось импортировать JSON");
      }
    }
    if (event.target.matches("[data-admin-form]")) {
      event.preventDefault();
      const data = new FormData(event.target);
      const id = `admin-${Date.now()}`;
      const custom = adminProducts();
      const uploaded = await imageFileToDataUrl(data.get("imageFile"));
      const price = Number(data.get("price")) || 0;
      const oldPrice = Number(data.get("oldPrice")) || Math.round(price * 1.18);
      const tags = String(data.get("tags") || data.get("collection") || "").split(",").map((tag) => tag.trim()).filter(Boolean);
      const item = product(id, data.get("name"), data.get("collection"), slugify(data.get("collection")), data.get("rarity"), price, oldPrice, uploaded || data.get("image"), Number(data.get("stock")) || 1, new Date().toISOString().slice(0, 10), data.get("short"), data.get("story") || data.get("short"), data.get("foil") || "Авторский фойл", data.get("condition") || "Mint", [86, 82, 88], tags.length ? tags : ["новинка"], data.get("status") || "new", data.get("sku") || nextLocalSku(custom.length), Number(data.get("run")) || 1);
      custom.unshift(item);
      write(STORE.admin, custom);
      toast("Карта добавлена в витрину");
      adminPage();
    }
  });
}

function slugify(value) {
  return String(value).toLowerCase().trim().replace(/[^a-zа-я0-9]+/gi, "-").replace(/^-|-$/g, "") || "custom";
}

const routes = { home, catalog, collections: collectionsPage, new: newPage, blog, article: articlePage, support, delivery: deliveryPage, returns: returnsPage, guide: guidePage, product: productPage, cart: cartPage, checkout: checkoutPage, thanks: thanksPage, compare: comparePage, account: accountPage, admin: adminPage, bundles: bundlesPage };

document.addEventListener("DOMContentLoaded", () => {
  bindGlobalEvents();
  const page = document.body.dataset.page || "home";
  (routes[page] || home)();
});
